// Tile size for shared memory optimization
#define TILE_SIZE 16

__global__ void matrixMulShared(float* A, float* B, float* C, 
                                int M, int N, int K) {
    // Shared memory for tiles
    __shared__ float tileA[TILE_SIZE][TILE_SIZE];
    __shared__ float tileB[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float sum = 0.0f;

    // Loop over tiles
    for (int t = 0; t < (K + TILE_SIZE - 1) / TILE_SIZE; t++) {
        // Load tiles into shared memory
        if (row < M && t * TILE_SIZE + threadIdx.x < K)
            tileA[threadIdx.y][threadIdx.x] = A[row * K + t * TILE_SIZE + threadIdx.x];
        else
            tileA[threadIdx.y][threadIdx.x] = 0.0f;

        if (col < N && t * TILE_SIZE + threadIdx.y < K)
            tileB[threadIdx.y][threadIdx.x] = B[(t * TILE_SIZE + threadIdx.y) * N + col];
        else
            tileB[threadIdx.y][threadIdx.x] = 0.0f;

        __syncthreads();  // Wait for tile loading

        // Compute partial dot product
        for (int i = 0; i < TILE_SIZE; i++)
            sum += tileA[threadIdx.y][i] * tileB[i][threadIdx.x];

        __syncthreads();  // Wait for computation before next tile
    }

    if (row < M && col < N)
        C[row * N + col] = sum;
}

// Parallel Reduction using OpenMP
// Computes sum of array elements in parallel

FUNCTION parallelReduction(array A, n):
    total = 0

    // Parallel section - divide work among threads
    PARALLEL REDUCTION(+:total)
        // Each thread gets chunk of array
        chunkSize = n / numThreads
        start = threadId * chunkSize
        end = min(start + chunkSize, n)

        // Each thread sums its portion
        localSum = 0
        FOR i FROM start TO end-1:
            localSum = localSum + A[i]

        // Reduction combines all local sums
        total = total + localSum

    RETURN total

// Using OpenMP pragma
int parallelSum(int* arr, int n) {
    int sum = 0;
    #pragma omp parallel for reduction(+:sum)
    for (int i = 0; i < n; i++) {
        sum += arr[i];
    }
    return sum;
}
